"""
prism.py — Unified Public API Facade

Single entry point for all PrismResonance operations.  Wires together
memory_map, compiler, engine, and sleep into one cohesive interface.

Typical usage
-------------
::

    from prismresonance import PrismResonance
    from prismresonance.frequency import FrequencyFamily

    prism = PrismResonance.create(embedding_dim=384)

    # Ingest a chunk
    prism.ingest(
        chunk_id="chunk_001",
        amplitude=my_encoder.encode("Database cluster ..."),
        frequency=FrequencyFamily.EMERGENCY,
    )

    # Query
    results = prism.query(
        query_amplitude=my_encoder.encode("connection error"),
        query_phase=FrequencyFamily.EMERGENCY,
        candidate_ids=["chunk_001", "chunk_002", ...],
        candidate_amplitudes=np.stack([...]),
    )

    # Consolidate (fast sleep)
    prism.sleep()

    # Shutdown (final checkpoint)
    prism.shutdown()
"""

from __future__ import annotations

import logging
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

from .compiler import compile_resonance_graph, DEFAULT_OUTPUT
from .engine import ResonanceEngine, ResonanceResult
from .frequency import FrequencyFamily
from .memory_map import ResonanceRegistry
from .sleep import SleepConfig, SleepManager

log = logging.getLogger("prismresonance")


class PrismResonance:
    """
    Unified facade — the only class most users need to import.

    Parameters
    ----------
    registry            : ResonanceRegistry instance (RAM sidecar).
    engine              : ResonanceEngine instance (ONNX inference).
    sleep_manager       : SleepManager instance (async consolidation).
    state_path          : Path to SQLite sidecar file.
    embedding_dim       : Expected embedding dimension N for validation.
    auto_sleep          : Start background sleep thread on init.
    sleep_interval      : Background consolidation interval in seconds.
    """

    def __init__(
        self,
        registry: ResonanceRegistry,
        engine: ResonanceEngine,
        sleep_manager: SleepManager,
        state_path: str | Path = "resonance_state.db",
        embedding_dim: Optional[int] = None,
        auto_sleep: bool = False,
        sleep_interval: float = 300.0,
    ) -> None:
        self._registry      = registry
        self._engine        = engine
        self._sleep_manager = sleep_manager
        self._state_path    = Path(state_path)
        self._embedding_dim = embedding_dim

        if auto_sleep:
            self._sleep_manager.start()

    # ── Factory ───────────────────────────────────────────────────────────

    @classmethod
    def create(
        cls,
        embedding_dim: int = 384,
        onnx_path: str | Path = DEFAULT_OUTPUT,
        state_path: str | Path = "resonance_state.db",
        coherence_threshold: float = 0.5,
        top_k_groups: int = 3,
        hebbian_rate: float = 0.02,
        auto_sleep: bool = False,
        sleep_interval: float = 300.0,
        recompile: bool = False,
        load_state: bool = True,
    ) -> "PrismResonance":
        """
        Build a fully wired PrismResonance instance.

        Parameters
        ----------
        embedding_dim       : Dimension N of source embeddings.
        onnx_path           : Where to write / load the ONNX graph.
        state_path          : SQLite sidecar path.
        coherence_threshold : Coherence shield cutoff (0–1).
        top_k_groups        : Groups to drill into at Level 1.
        hebbian_rate        : Real-time phase shift strength (0 to disable).
        auto_sleep          : Start background consolidation immediately.
        sleep_interval      : Consolidation interval (seconds).
        recompile           : Force recompile the ONNX graph even if it exists.
        load_state          : Load existing sidecar state on startup.
        """
        onnx_path = Path(onnx_path)
        if recompile or not onnx_path.exists():
            log.info("Compiling ONNX wave-math graph -> %s", onnx_path)
            compile_resonance_graph(embedding_dim, onnx_path)

        registry = ResonanceRegistry()

        if load_state:
            sp = Path(state_path)
            if sp.exists():
                log.info("Loading sidecar state from %s", sp)
                registry.load_state(sp)

        engine = ResonanceEngine(
            onnx_path=onnx_path,
            registry=registry,
            coherence_threshold=coherence_threshold,
            top_k_groups=top_k_groups,
            hebbian_rate=hebbian_rate,
        )

        sleep_cfg = SleepConfig(
            state_path=str(state_path),
            interval_seconds=sleep_interval,
        )
        sleep_mgr = SleepManager(registry, sleep_cfg)

        return cls(
            registry=registry,
            engine=engine,
            sleep_manager=sleep_mgr,
            state_path=state_path,
            embedding_dim=embedding_dim,
            auto_sleep=auto_sleep,
            sleep_interval=sleep_interval,
        )

    # ── Validation ────────────────────────────────────────────────────────

    def _validate_amplitude(self, amplitude: np.ndarray, label: str = "amplitude") -> None:
        """Raise ValueError if amplitude shape doesn't match compiled dim."""
        if self._embedding_dim is not None and amplitude.shape[-1] != self._embedding_dim:
            raise ValueError(
                f"{label} has shape {amplitude.shape}, expected last dim "
                f"{self._embedding_dim} (the compiled embedding_dim). "
                f"Re-create with PrismResonance.create(embedding_dim={amplitude.shape[-1]}) "
                f"or recompile the ONNX graph."
            )

    # ── Ingestion ─────────────────────────────────────────────────────────

    def ingest(
        self,
        chunk_id: str,
        amplitude: np.ndarray,
        frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL,
        parent_id: Optional[str] = None,
        group_id: Optional[str] = None,
    ) -> None:
        """
        Register a new chunk from the source database into the sidecar.

        Raises ValueError if amplitude.shape[0] does not match the compiled
        embedding_dim — catches encoder/model mismatches before they corrupt
        the ONNX computation graph at inference time.
        """
        self._validate_amplitude(amplitude, f"chunk '{chunk_id}' amplitude")
        self._registry.surf_and_flag(
            chunk_id=chunk_id,
            amplitude=amplitude,
            active_phase=float(frequency),
            parent_id=parent_id,
            group_id=group_id,
        )

    def ingest_batch(
        self,
        chunk_ids: List[str],
        amplitudes: np.ndarray,
        frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL,
    ) -> None:
        """Ingest multiple chunks at once under the same FrequencyFamily."""
        self._validate_amplitude(amplitudes, "batch amplitudes")
        phi = float(frequency)
        for i, cid in enumerate(chunk_ids):
            self._registry.surf_and_flag(
                chunk_id=cid,
                amplitude=amplitudes[i],
                active_phase=phi,
            )

    # ── Mutation API ──────────────────────────────────────────────────────

    def delete_chunk(self, chunk_id: str) -> bool:
        """
        Remove a chunk from the sidecar registry.

        Cleans up ChunkMeta, amplitude cache, group membership, and all
        co-activation pairs that reference this chunk.

        Returns True if the chunk existed and was removed.
        """
        return self._registry.delete_chunk(chunk_id)

    def update_chunk(
        self,
        chunk_id: str,
        new_amplitude: Optional[np.ndarray] = None,
        new_frequency: Optional[FrequencyFamily | float] = None,
    ) -> bool:
        """
        Update a chunk's amplitude and/or operational frequency in place.

        If new_frequency causes the chunk to move to a different phase band,
        it is automatically reassigned to the appropriate group.

        Returns True if the chunk existed and was updated.
        """
        if new_amplitude is not None:
            self._validate_amplitude(new_amplitude, f"update for chunk '{chunk_id}'")
        return self._registry.update_chunk(chunk_id, new_amplitude, new_frequency)

    # ── Context control ───────────────────────────────────────────────────

    def set_frequency(self, family: FrequencyFamily | float) -> None:
        """Broadcast a new operational frequency to the live session."""
        self._registry.set_active_frequency(family)
        log.debug("Active frequency set to %.4f (%s)",
                  float(family),
                  FrequencyFamily.nearest(float(family)).name)

    # ── Retrieval ─────────────────────────────────────────────────────────

    def query(
        self,
        query_amplitude: np.ndarray,
        query_phase: FrequencyFamily | float,
        candidate_ids: List[str],
        candidate_amplitudes: np.ndarray,
        flat: bool = False,
    ) -> List[ResonanceResult]:
        """
        Two-level resonance retrieval.

        Parameters
        ----------
        query_amplitude      : (N,) float32 — query embedding.
        query_phase          : Operational phase for this query.
        candidate_ids        : Chunk IDs pulled from the read-only source DB.
        candidate_amplitudes : (M, N) float32 — corresponding embeddings.
        flat                 : Skip group scan; use single-level scan instead.

        Returns
        -------
        List[ResonanceResult] sorted by score descending, all above T_c.
        """
        phi = float(query_phase)
        if flat:
            return self._engine.query_flat(
                query_amplitude, phi, candidate_ids, candidate_amplitudes)
        return self._engine.query_resonance(
            query_amplitude, phi, candidate_ids, candidate_amplitudes)

    def record_co_activation(self, id_a: str, id_b: str) -> None:
        """
        Signal that two chunks were used together in an agent interaction.
        Accumulates in the Most Related index for sleep-cycle consolidation.
        """
        self._registry.record_co_activation(id_a, id_b)

    # ── Index query APIs ──────────────────────────────────────────────────

    def most_recent(self, n: int = 10) -> List[Tuple[str, float]]:
        """
        Most Recent Index — return the n most recently accessed chunks.

        Returns
        -------
        List of (chunk_id, last_access_unix_timestamp) sorted newest first.
        """
        return self._registry.most_recent(n)

    def most_related(self, chunk_id: str, n: int = 10) -> List[Tuple[str, int]]:
        """
        Most Related Index — return the n chunks most co-activated with chunk_id.

        Returns
        -------
        List of (partner_chunk_id, co_activation_count) sorted highest first.
        """
        return self._registry.most_related(chunk_id, n)

    # ── Memory consolidation ──────────────────────────────────────────────

    def sleep(self) -> None:
        """Run one full consolidation cycle synchronously (fast sleep)."""
        self._sleep_manager.fast_sleep()

    def start_background_sleep(self) -> None:
        """Start the background consolidation timer thread."""
        self._sleep_manager.start()

    def stop_background_sleep(self, flush: bool = True) -> None:
        """Stop the background thread and optionally flush state."""
        self._sleep_manager.stop(flush=flush)

    # ── Persistence ───────────────────────────────────────────────────────

    def save(self, path: Optional[str | Path] = None) -> None:
        """Flush current registry state to the sidecar file."""
        self._registry.save_state(path or self._state_path)

    def load(self, path: Optional[str | Path] = None) -> None:
        """Reload registry from sidecar file (replaces current RAM state)."""
        self._registry.load_state(path or self._state_path)

    def shutdown(self) -> None:
        """Stop background thread and perform final checkpoint."""
        log.info("PrismResonance shutting down — final checkpoint")
        self._sleep_manager.stop(flush=True)

    # ── Inspection ────────────────────────────────────────────────────────

    @property
    def registry(self) -> ResonanceRegistry:
        return self._registry

    @property
    def engine(self) -> ResonanceEngine:
        return self._engine

    @property
    def embedding_dim(self) -> Optional[int]:
        return self._embedding_dim

    def status(self) -> Dict:
        """Return a summary of current registry state."""
        groups = self._registry.all_groups()
        return {
            "chunks":      len(self._registry.all_chunk_ids()),
            "groups":      len(groups),
            "active_phase": self._registry.active_phase,
            "active_family": FrequencyFamily.nearest(
                self._registry.active_phase).name,
            "embedding_dim": self._embedding_dim,
            "group_summary": {
                gid: {
                    "members": len(g.member_ids),
                    "phi":     round(g.phi, 4),
                    "staleness_s": round(g.staleness(), 1),
                }
                for gid, g in groups.items()
            },
        }
